import{_ as e,c as i,o as l,ae as o}from"./chunks/framework.CEJdHl6x.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"linklocation/redis.md","filePath":"linklocation/redis.md"}'),a={name:"linklocation/redis.md"};function u(s,t,n,q,r,g){return l(),i("div",null,t[0]||(t[0]=[o('<h2 id="性能测试" tabindex="-1">性能测试 <a class="header-anchor" href="#性能测试" aria-label="Permalink to &quot;性能测试&quot;">​</a></h2><p>redis-benchmark -h localhost -p 6379 -c 100 -n 100000</p><h2 id="redis-cli" tabindex="-1">redis-cli <a class="header-anchor" href="#redis-cli" aria-label="Permalink to &quot;redis-cli&quot;">​</a></h2><p>默认16个数据库 127.0.0.1:6379&gt; ping // 测试服务是否正常 PONG 127.0.0.1:6379&gt; set name dffdsaf // 设置key OK 127.0.0.1:6379&gt; get name // 获取key &quot;dffdsaf&quot; 127.0.0.1:6379&gt; keys * // 查看所有key</p><ol><li>&quot;name&quot; 127.0.0.1:6379&gt; select 3 // 选择数据库 OK 127.0.0.1:6379[3]&gt; keys * // 查看所有key (empty list or set) 127.0.0.1:6379[3]&gt; get name // 获取key (nil) 127.0.0.1:6379[3]&gt; select 0 // 选择数据库 OK 127.0.0.1:6379&gt; get name // 获取key &quot;dffdsaf&quot; 127.0.0.1:6379&gt; flushdb // 清空当前数据库 OK 127.0.0.1:6379&gt; get name // 获取key (nil) 127.0.0.1:6379&gt; flushall // 清空所有数据库 OK 127.0.0.1:6379&gt; exists name // 查看key是否存在 (integer) 0 127.0.0.1:6379&gt; set name 123456 // 设置key OK 127.0.0.1:6379&gt; exists name // 查看key是否存在 (integer) 1 127.0.0.1:6379&gt; expire name 10 // 设置key的过期时间 (integer) 1 127.0.0.1:6379&gt; ttl name // 查看key的剩余时间 (integer) 5 127.0.0.1:6379&gt; ttl name // 查看key的剩余时间 (integer) -2 // -2表示key不存在 127.0.0.1:6379&gt; type name // 查看key的类型 string 127.0.0.1:6379&gt; append name 45678454 // 追加字符串,如果key不存在则创建 (integer) 12 127.0.0.1:6379&gt; type name // 查看key的类型 string 127.0.0.1:6379&gt; get nema // 获取key (nil) 127.0.0.1:6379&gt; get name // 获取key &quot;125545678454&quot;</li></ol><h2 id="字符串" tabindex="-1">字符串 <a class="header-anchor" href="#字符串" aria-label="Permalink to &quot;字符串&quot;">​</a></h2><p>127.0.0.1:6379&gt; strlen name // 获取字符串的长度 (integer) 12 127.0.0.1:6379&gt; incr name // 自增 (integer) 125545678455 127.0.0.1:6379&gt; incr name // 自增 (integer) 125545678456 127.0.0.1:6379&gt; decr name // 自减 (integer) 125545678455 127.0.0.1:6379&gt; decr name // 自减 (integer) 125545678454 127.0.0.1:6379&gt; incrby name 10 // 自增,自增指定数值 (integer) 125545678464 127.0.0.1:6379&gt; incr name // 自增,步长10 (integer) 125545678465 127.0.0.1:6379&gt;decrby name 10 // 自减,自减指定数值 127.0.0.1:6379&gt; getrange name 0 4 // 获取指定范围的字符串 &quot;12554&quot; 127.0.0.1:6379&gt; setrange name 1 fdsf // 设置指定位置的字符串 (integer) 12 127.0.0.1:6379&gt; setex name2 20 &#39;fasfdsa&#39; // 设置key,并设置过期时间 OK 127.0.0.1:6379&gt; get name2 // 获取key &quot;fasfdsa&quot; 127.0.0.1:6379&gt; ttl name2 // 查看key的剩余时间 127.0.0.1:6379&gt; setnx name2 fsdafsd // 设置key,如果key不存在则创建 (integer) 1 127.0.0.1:6379&gt; get name2 &quot;fsdafsd&quot; 127.0.0.1:6379&gt; setnx name2 fsdafsd // 尝试设置key,如果key已存在则返回0 (integer) 0 127.0.0.1:6379&gt; mset n1 df n2 sd n3 se // 设置多个key OK 127.0.0.1:6379&gt; keys *</p><ol><li>&quot;n1&quot;</li><li>&quot;n2&quot;</li><li>&quot;name&quot;</li><li>&quot;n3&quot;</li><li>&quot;value&quot;</li><li>&quot;name2&quot; 127.0.0.1:6379&gt; mget n1 n2 n3 // 获取多个key</li><li>&quot;df&quot;</li><li>&quot;sd&quot;</li><li>&quot;se&quot; 127.0.0.1:6379&gt; msetnx n1 sdfd2 n4 sfd // 尝试设置多个key,如果key已存在则返回0，同时成功和失败 (integer) 0 127.0.0.1:6379&gt; get n4 (nil) 127.0.0.1:6379&gt; mset user:1 {name:dd,age:3} OK 127.0.0.1:6379&gt; get user:1:name (nil) 127.0.0.1:6379&gt; get user:1:name (nil) 127.0.0.1:6379&gt; mset user2:1:name sdfe user2:1:age 14 OK 127.0.0.1:6379&gt; mget user2:1:name user2:1:age</li><li>&quot;sdfe&quot;</li><li>&quot;14&quot; 127.0.0.1:6379&gt; mget user:1</li><li>&quot;{name:dd,age:3}&quot; 127.0.0.1:6379&gt; getset db redis // 设置key并返回旧值 (nil) 127.0.0.1:6379&gt; get db // 获取key &quot;redis&quot; 127.0.0.1:6379&gt; getset db rediss // 设置key并返回旧值 &quot;redis&quot; 127.0.0.1:6379&gt; get db // 获取key &quot;rediss&quot;</li></ol><h2 id="列表" tabindex="-1">列表 <a class="header-anchor" href="#列表" aria-label="Permalink to &quot;列表&quot;">​</a></h2><p>127.0.0.1:6379&gt; lpush list 0 // 添加元素,从左到右 (integer) 1 127.0.0.1:6379&gt; lpush list 1 // 添加元素,从左到右 (integer) 2 127.0.0.1:6379&gt; lpush list 3 // 添加元素,从左到右 (integer) 3 127.0.0.1:6379&gt; lrange list 0 -1 // 获取列表中所有元素</p><ol><li>&quot;3&quot;</li><li>&quot;1&quot;</li><li>&quot;0&quot; 127.0.0.1:6379&gt; lrange list 0 1 // 获取列表中指定范围元素</li><li>&quot;3&quot;</li><li>&quot;1&quot; 127.0.0.1:6379&gt; rpush list 4 // 添加元素,从右到左 (integer) 4 127.0.0.1:6379&gt; lrange list 0 -1 // 获取列表中所有元素</li><li>&quot;3&quot;</li><li>&quot;1&quot;</li><li>&quot;0&quot;</li><li>&quot;4&quot;</li></ol><p>127.0.0.1:6379&gt; lpop list // 从列表中弹出元素,从左到右 &quot;3&quot; 127.0.0.1:6379&gt; lrange list 0 -1 // 获取列表中所有元素</p><ol><li>&quot;1&quot;</li><li>&quot;0&quot;</li><li>&quot;4&quot; 127.0.0.1:6379&gt; rpop list // 从列表中弹出元素,从右到左 &quot;4&quot; 127.0.0.1:6379&gt; lrange list 0 -1 // 获取列表中所有元素</li><li>&quot;1&quot;</li><li>&quot;0&quot; 127.0.0.1:6379&gt; lindex list 0 // 获取列表中指定索引的元素 &quot;1&quot; 127.0.0.1:6379&gt; llen list // 获取列表的长度 (integer) 2 127.0.0.1:6379&gt; lrem list 1 0 // 删除列表中指定元素,返回删除的个数 (integer) 1 127.0.0.1:6379&gt; lrange list 0 -1 // 获取列表中所有元素</li><li>&quot;1&quot; 127.0.0.1:6379&gt; lrem list 2 0 // 删除列表中2个元素，删除count&#39;为0时，删除所有元素 (integer) 1 127.0.0.1:6379&gt; lrange list 0 -1 // 获取列表中所有元素</li><li>&quot;47&quot;</li><li>&quot;3&quot;</li><li>&quot;4&quot;</li><li>&quot;1&quot; 127.0.0.1:6379&gt; ltrim list 0 1 // 截取列表中指定范围元素 OK 127.0.0.1:6379&gt; lrange list 0 -1 // 获取列表中所有元素</li><li>&quot;47&quot;</li><li>&quot;3&quot; 127.0.0.1:6379&gt; lrange list 0 -1 // 获取列表中所有元素</li><li>&quot;44&quot;</li><li>&quot;44&quot;</li><li>&quot;47&quot;</li><li>&quot;3&quot; 127.0.0.1:6379&gt; rpoplpush list fe // 移除列表中的元素，并返回移除的元素，并添加到另一个列表中，另一个列表如果不存在，则创建 &quot;3&quot; 127.0.0.1:6379&gt; lrange list 0 -1 // 获取列表中所有元素</li><li>&quot;44&quot;</li><li>&quot;44&quot;</li><li>&quot;47&quot; 127.0.0.1:6379&gt; lrange fe 0 -1 // 获取列表中所有元素</li><li>&quot;3&quot; 127.0.0.1:6379&gt; lset list 0 df // 修改列表中指定索引的元素 OK 127.0.0.1:6379&gt; lrange list 0 -1 // 获取列表中所有元素</li><li>&quot;df&quot;</li><li>&quot;44&quot;</li><li>&quot;47&quot; 127.0.0.1:6379&gt; lset list 3 sd // 修改列表中指定索引的元素,如果索引不存在，则返回错误 (error) ERR index out of range 127.0.0.1:6379&gt; linsert list before 44 fdsf // 在指定元素之前插入元素 (integer) 4 127.0.0.1:6379&gt; lrange list 0 -1 // 获取列表中所有元素</li><li>&quot;df&quot;</li><li>&quot;fdsf&quot;</li><li>&quot;44&quot;</li><li>&quot;47&quot; 127.0.0.1:6379&gt; linsert list after 44 fdsf // 在指定元素之后插入元素 (integer) 5 127.0.0.1:6379&gt; lrange list 0 -1 // 获取列表中所有元素</li><li>&quot;df&quot;</li><li>&quot;fdsf&quot;</li><li>&quot;44&quot;</li><li>&quot;fdsf&quot;</li><li>&quot;47&quot;</li></ol><h2 id="set" tabindex="-1">set <a class="header-anchor" href="#set" aria-label="Permalink to &quot;set&quot;">​</a></h2><p>127.0.0.1:6379&gt; sadd set 11 // 添加元素 (integer) 1 127.0.0.1:6379&gt; sadd set 12 // 添加元素 (integer) 1 127.0.0.1:6379&gt; sadd set 13 // 添加元素 (integer) 1 127.0.0.1:6379&gt; smembers set // 获取set中的所有元素</p><ol><li>&quot;11&quot;</li><li>&quot;12&quot;</li><li>&quot;13&quot; 127.0.0.1:6379&gt; sismember set fff // 判断元素是否在set中 (integer) 0 127.0.0.1:6379&gt; sismember set 12 // 判断元素是否在set中 (integer) 1 127.0.0.1:6379&gt; scard set // 获取set中的元素个数 (integer) 3 127.0.0.1:6379&gt; srem set 12 // 删除元素12 (integer) 1 127.0.0.1:6379&gt; smembers set // 获取set中的所有元素</li><li>&quot;11&quot;</li><li>&quot;13 127.0.0.1:6379&gt; srandmember set // 获取set中的随机元素 &quot;13&quot; 127.0.0.1:6379&gt; srandmember set // 获取set中的随机元素 &quot;11&quot; 127.0.0.1:6379&gt; spop set // 获取set中的随机元素并删除 &quot;13&quot; 127.0.0.1:6379&gt; smembers set1 // 获取set中的所有元素</li><li>&quot;1&quot;</li><li>&quot;2&quot;</li><li>&quot;3&quot; 127.0.0.1:6379&gt; smove set1 set2 1 // 移动元素1到set2中,如果set2不存在，则创建 (integer) 1 127.0.0.1:6379&gt; smembers set2 // 获取set中的所有元素</li><li>&quot;1&quot; 127.0.0.1:6379&gt; smembers set1 // 获取set中的所有元素</li><li>&quot;2&quot;</li><li>&quot;3&quot; 127.0.0.1:6379&gt; smembers set2 // 获取set中的所有元素</li><li>&quot;3&quot;</li><li>&quot;4&quot;</li><li>&quot;5&quot; 127.0.0.1:6379&gt; smembers set1 // 获取set中的所有元素</li><li>&quot;1&quot;</li><li>&quot;2&quot;</li><li>&quot;3&quot; 127.0.0.1:6379&gt; sdiff set1 set2 // 获取set1和set2的差集</li><li>&quot;1&quot;</li><li>&quot;2&quot; 127.0.0.1:6379&gt; sunion set1 set2 // 获取set1和set2的并集</li><li>&quot;1&quot;</li><li>&quot;2&quot;</li><li>&quot;3&quot;</li><li>&quot;4&quot;</li><li>&quot;5&quot; 127.0.0.1:6379&gt; sinter set1 set2 // 获取set1和set2的交集</li><li>&quot;3&quot;</li></ol><h2 id="hash-哈希" tabindex="-1">hash 哈希 <a class="header-anchor" href="#hash-哈希" aria-label="Permalink to &quot;hash 哈希&quot;">​</a></h2><p>127.0.0.1:6379&gt; hset hash name value1 // 添加元素 (integer) 1 127.0.0.1:6379&gt; hset hash name value1 // 添加元素,如果元素已存在则返回0 (integer) 0 127.0.0.1:6379&gt; hset hash name2 value1 // 添加元素,如果元素已存在则返回0 (integer) 1 127.0.0.1:6379&gt; hget hash name // 获取元素 &quot;value1&quot; 127.0.0.1:6379&gt; hget hash name2 // 获取元素 &quot;value1&quot; 127.0.0.1:6379&gt; hmset hash name3 value3 name4 value4 // 添加多个元素 OK 127.0.0.1:6379&gt; hmget hash name name2 name3 name4 // 获取多个元素</p><ol><li>&quot;value1&quot;</li><li>&quot;value1&quot;</li><li>&quot;value3&quot;</li><li>&quot;value4&quot; 127.0.0.1:6379&gt; hgetall hash // 获取所有元素</li><li>&quot;name&quot;</li><li>&quot;value1&quot;</li><li>&quot;name2&quot;</li><li>&quot;value1&quot;</li><li>&quot;name3&quot;</li><li>&quot;value3&quot;</li><li>&quot;name4&quot;</li><li>&quot;value4&quot; 127.0.0.1:6379&gt; hdel hash name3 // 删除元素 (integer) 1 127.0.0.1:6379&gt; hgetall hash // 获取所有元素</li><li>&quot;name&quot;</li><li>&quot;value1&quot;</li><li>&quot;name4&quot;</li><li>&quot;value4&quot; 127.0.0.1:6379&gt; hlen hash // 获取元素个数 (integer) 2 127.0.0.1:6379&gt; hexists hash name1 // 判断元素是否存在 (integer) 0 127.0.0.1:6379&gt; hexists hash name4 // 判断元素是否存在 (integer) 1 127.0.0.1:6379&gt; hkeys hash // 获取所有元素的key</li><li>&quot;name&quot;</li><li>&quot;name4&quot; 127.0.0.1:6379&gt; hvals hash // 获取所有元素的value</li><li>&quot;value1&quot;</li><li>&quot;value4&quot; 127.0.0.1:6379&gt; hgetall hash // 获取所有元素</li><li>&quot;name&quot;</li><li>&quot;value1&quot;</li><li>&quot;name4&quot;</li><li>&quot;value4&quot;</li><li>&quot;name2&quot;</li><li>&quot;1&quot; 127.0.0.1:6379&gt; hincrby hash name2 44 // 递增元素 (integer) 45 127.0.0.1:6379&gt; hgetall hash // 获取所有元素</li><li>&quot;name&quot;</li><li>&quot;value1&quot;</li><li>&quot;name4&quot;</li><li>&quot;value4&quot;</li><li>&quot;name2&quot;</li><li>&quot;45&quot; 127.0.0.1:6379&gt; hsetnx hash2 name 1 // 添加元素,如果元素已存在则返回0,不存在就创建并添加 (integer) 1 127.0.0.1:6379&gt; hgetall hash2 // 获取所有元素</li><li>&quot;name&quot;</li><li>&quot;1&quot; 127.0.0.1:6379&gt; hincrby hash name2 -4 // 递减元素 (integer) 41 127.0.0.1:6379&gt; hgetall hash // 获取所有元素</li><li>&quot;name&quot;</li><li>&quot;value1&quot;</li><li>&quot;name4&quot;</li><li>&quot;value4&quot;</li><li>&quot;name2&quot;</li><li>&quot;41&quot;</li></ol><h2 id="geo" tabindex="-1">geo <a class="header-anchor" href="#geo" aria-label="Permalink to &quot;geo&quot;">​</a></h2><p>127.0.0.1:6379&gt; geoadd china:city 116.04 39.90 beijin // 添加元素 (integer) 1 127.0.0.1:6379&gt; geoadd china:city 112.04 39.90 beijin2 113.04 56.5 beijin3 // 添加多个元素 (integer) 2 127.0.0.1:6379&gt; geopos china:city beijin // 获取元素位置</p><ol><li><ol><li>&quot;116.03999823331832886&quot;</li><li>&quot;39.90000009167092543&quot; 127.0.0.1:6379&gt; geodist china:city beijin beijin2 // 获取两个元素之间的距离 &quot;341287.2173&quot; 127.0.0.1:6379&gt; geodist china:city beijin beijin2 km // 获取两个元素之间的距离,单位为公里 &quot;341.2872&quot; 127.0.0.1:6379&gt; georadius china:city 112 30 500 km // 获取元素半径内元素 (empty list or set) 127.0.0.1:6379&gt; georadius china:city 112 30 1000 km // 获取元素半径内元素 (empty list or set) 127.0.0.1:6379&gt; georadius china:city 112 30 2000 km // 获取元素半径内元素</li></ol></li><li>&quot;beijin2&quot;</li><li>&quot;beijin&quot; 127.0.0.1:6379&gt; georadius china:city 112 30 2000 km withdist // 获取元素半径内元素和距离</li><li><ol><li>&quot;beijin2&quot;</li><li>&quot;1101.1464&quot;</li></ol></li><li><ol><li>&quot;beijin&quot;</li><li>&quot;1160.7383&quot; 127.0.0.1:6379&gt; georadius china:city 112 30 2000 km withcoord // 获取元素半径内元素和坐标</li></ol></li><li><ol><li>&quot;beijin2&quot;</li><li><ol><li>&quot;112.03999847173690796&quot;</li><li>&quot;39.90000009167092543&quot;</li></ol></li></ol></li><li><ol><li>&quot;beijin&quot;</li><li><ol><li>&quot;116.03999823331832886&quot;</li><li>&quot;39.90000009167092543&quot; 127.0.0.1:6379&gt; georadius china:city 112 30 2000 km withcoord count 1 // 获取元素半径内元素和坐标,只返回一个元素</li></ol></li></ol></li><li><ol><li>&quot;beijin2&quot;</li><li><ol><li>&quot;112.03999847173690796&quot;</li><li>&quot;39.90000009167092543 127.0.0.1:6379&gt; georadiusbymember china:city beijin2 1000 km // 获取元素半径内元素</li></ol></li></ol></li><li>&quot;beijin2&quot;</li><li>&quot;beijin&quot; 127.0.0.1:6379&gt; zrange china:city 0 -1 // 获取元素</li><li>&quot;beijin2&quot;</li><li>&quot;beijin&quot;</li><li>&quot;beijin3&quot; 127.0.0.1:6379&gt; zrem china:city beijin // 删除元素 (integer) 1 127.0.0.1:6379&gt; zrange china:city 0 -1 // 获取元素</li><li>&quot;beijin2&quot;</li><li>&quot;beijin3&quot;</li></ol><h2 id="bitmap" tabindex="-1">bitmap <a class="header-anchor" href="#bitmap" aria-label="Permalink to &quot;bitmap&quot;">​</a></h2><p>setbit sign 1 0 // 设置位 (integer) 0 127.0.0.1:6379&gt; setbit sign 1 1 // 设置位 (integer) 0 127.0.0.1:6379&gt; setbit sign 2 3 // 错误,位必须为0或1 (error) ERR bit is not an integer or out of range 127.0.0.1:6379&gt; setbit sign 2 0 // 设置位 (integer) 0 127.0.0.1:6379&gt; getbit sign 1 // 获取位 (integer) 1 127.0.0.1:6379&gt; getbit sign 2 // 获取位 (integer) 0 127.0.0.1:6379&gt; bitcount sign // 获取全部位为1的个数 (integer) 1 127.0.0.1:6379&gt; setbit sign 3 1 // 错误,位必须为0或1 (integer) 0 127.0.0.1:6379&gt; bitcount sign // 获取全部位为1的个数 (integer) 2</p><h2 id="事务" tabindex="-1">事务 <a class="header-anchor" href="#事务" aria-label="Permalink to &quot;事务&quot;">​</a></h2><p>127.0.0.1:6379&gt; multi // 开启事务 OK 127.0.0.1:6379&gt; set k1 ss // 添加命令 QUEUED 127.0.0.1:6379&gt; set k2 de // 添加命令 QUEUED 127.0.0.1:6379&gt; get k1 // 添加命令 QUEUED 127.0.0.1:6379&gt; set k3 deag // 添加命令 QUEUED 127.0.0.1:6379&gt; exec // 执行事务</p><ol><li>OK</li><li>OK</li><li>&quot;ss&quot;</li><li>OK 127.0.0.1:6379&gt; discard // 取消事务</li></ol><p>127.0.0.1:6379&gt; set value 11 // 添加命令 OK 127.0.0.1:6379&gt; multi // 开启事务 OK 127.0.0.1:6379&gt; incrby value 10 // 添加命令 QUEUED 127.0.0.1:6379&gt; get value // 添加命令 QUEUED 127.0.0.1:6379&gt; exec // 执行事务</p><ol><li>(integer) 31</li><li>&quot;31&quot; 127.0.0.1:6379&gt; watch value // 监听value OK 127.0.0.1:6379&gt; multi // 开启事务 OK 127.0.0.1:6379&gt; incrby value 10 // 添加命令 QUEUED 127.0.0.1:6379&gt; exec // 执行事务 (nil) 127.0.0.1:6379&gt; unwatch // 取消监听 OK</li></ol><h2 id="rdb和aof" tabindex="-1">rdb和aof <a class="header-anchor" href="#rdb和aof" aria-label="Permalink to &quot;rdb和aof&quot;">​</a></h2><p>rdb: redis数据保存文件,定期快照机制，将内存中的数据集写入磁盘。 aof: append only file,追加日志文件，记录每个写操作命令，以日志形式追加到文件末尾 RDB：占用空间较小，恢复速度快，但可能存在数据丢失风险 AOF：数据更安全，可读性好，但文件体积较大，恢复速度相对较慢 ，有aof-check命令，可以检查aof文件</p><h2 id="发布订阅" tabindex="-1">发布订阅 <a class="header-anchor" href="#发布订阅" aria-label="Permalink to &quot;发布订阅&quot;">​</a></h2><p>127.0.0.1:6379&gt; subscribe channel // 订阅channel</p><ol><li>&quot;subscribe&quot;</li><li>&quot;channel&quot; 127.0.0.1:6379&gt; publish channel message // 发布消息 (integer) 1 127.0.0.1:6379&gt; subscribe channel1 channel2 channel3 // 订阅多个channel</li><li>&quot;subscribe&quot;</li><li>&quot;channel1&quot;</li></ol><h2 id="集群" tabindex="-1">集群 <a class="header-anchor" href="#集群" aria-label="Permalink to &quot;集群&quot;">​</a></h2><p>windows命令:redis-server.exe redis.windows.conf // 启动集群 windows命令:redis-cli -h 127.0.0.1 -p 6379 // 连接集群</p><p>127.0.0.1:6379&gt; info replication // 获取集群信息 role:master // 当前节点角色,主机master、从机slave connected_slaves:0 // 当前节点的从机数量 master_replid:54e68af95f29e711cb8f2df1fef4b224cc6c442d master_replid2:0000000000000000000000000000000000000000 master_repl_offset:0 second_repl_offset:-1 repl_backlog_active:0 repl_backlog_size:1048576 repl_backlog_first_byte_offset:0 repl_backlog_histlen:0</p><p>127.0.0.1:6381&gt; slaveof 127.0.0.1 6379 // 配置从机 OK 127.0.0.1:6381&gt; info replication // 获取集群信息 role:slave // 当前节点角色,主机master、从机slave master_host:127.0.0.1 // 从机的主机地址 master_port:6379 // 从机的端口号 master_link_status:up // 从机的连接状态 master_last_io_seconds_ago:2 master_sync_in_progress:0 slave_repl_offset:42 slave_priority:100 slave_read_only:1 connected_slaves:0 master_replid:b8074c3544fafbc14aad4d738eb45e81e3766dc7 master_replid2:0000000000000000000000000000000000000000 master_repl_offset:42 second_repl_offset:-1 repl_backlog_active:1 repl_backlog_size:1048576 repl_backlog_first_byte_offset:43 repl_backlog_histlen:0</p><p>127.0.0.1:6379&gt; info replication role:master connected_slaves:2 // 当前节点的从机数量 slave0:ip=127.0.0.1,port=6380,state=online,offset=98,lag=0 // 从机的信息 slave1:ip=127.0.0.1,port=6381,state=online,offset=98,lag=0 // 从机的信息 master_replid:b8074c3544fafbc14aad4d738eb45e81e3766dc7 master_replid2:0000000000000000000000000000000000000000 master_repl_offset:98 second_repl_offset:-1 repl_backlog_active:1 repl_backlog_size:1048576 repl_backlog_first_byte_offset:1 repl_backlog_histlen:98</p><p>主机如果断了,那么就没有写入的操作,但从机依然有数据可以读取 当主机重新链接后,从机会依然会从主机中获取数据 当从机断开后，主机写入的数据，在从机重新连接后，依然会获取到断开时的数据，注意通过命令行配置的主机需要重新命令连接，而配置文件不需要。 全量复制: 主机写入数据后，从机通过内存数据库进行全量复制 从机连接主机，获取全量数据 增量复制: 主机写入数据后，从机通过主机的修改命令依次执行获取数据 主机增加数据，从机同步</p><p>从机连接到主机后，会发送一个async同步命令，主机在接收后会启动后台的存盘进程，同时收集所有的修改命令，在后台执行完成后，传送整个数据包给从机 当前的模式默认是一对多主从更关系，如果使用链表式 6379&lt;--6380&lt;--6381 的主从关系，依然只有一个主机，中间的服务依然是从机，但主机断了后，从机可以通过命令slaveof no one来自己当主机。</p><h4 id="主机" tabindex="-1">主机: <a class="header-anchor" href="#主机" aria-label="Permalink to &quot;主机:&quot;">​</a></h4><p>127.0.0.1:6379&gt; keys * (empty list or set) 127.0.0.1:6379&gt; keys * (empty list or set) 127.0.0.1:6379&gt; set name 123 // 主机可以执行写操作 OK 127.0.0.1:6379&gt; keys *</p><ol><li>&quot;name&quot;</li></ol><h4 id="从机" tabindex="-1">从机 <a class="header-anchor" href="#从机" aria-label="Permalink to &quot;从机&quot;">​</a></h4><p>127.0.0.1:6380&gt; keys * (empty list or set) 127.0.0.1:6380&gt; keys * // 从机可以执行读操作，可以获取到主机的数据</p><ol><li>&quot;name&quot; 127.0.0.1:6380&gt; get name &quot;123&quot; 127.0.0.1:6380&gt; set name //从机不能执行写操作 (error) ERR wrong number of arguments for &#39;set&#39; command 127.0.0.1:6380&gt;</li></ol><h2 id="哨兵" tabindex="-1">哨兵 <a class="header-anchor" href="#哨兵" aria-label="Permalink to &quot;哨兵&quot;">​</a></h2><p>创建哨兵配置文件 sentinel.conf: sentinel monitor mymaster 127.0.0.1 6379 2 // 创建一个名称为mymaster的主机，主机地址为127.0.0.1，端口6379，从机数量为2 sentinel sentinel.conf // 启动哨兵 127.0.0.1:26379&gt; sentinel masters // 获取所有哨兵的配置信息</p><ol><li>&quot;name&quot;</li><li>&quot;ip&quot;</li><li>&quot;port&quot;</li></ol><h3 id="哨兵集群" tabindex="-1">哨兵集群 <a class="header-anchor" href="#哨兵集群" aria-label="Permalink to &quot;哨兵集群&quot;">​</a></h3><p>创建哨兵配置文件 sentinel.conf: port 26379 // 端口号 daemonize yes // 运行为守护进程 logfile &quot;sentinel.log&quot; // 日志文件 dir &quot;/tmp&quot; // 运行目录</p><p>监控主节点 sentinel monitor mymaster 127.0.0.1 6379 2 // 创建一个名称为mymaster的主机，主机地址为127.0.0.1，端口6379，从机数量为2 sentinel down-after-milliseconds mymaster 5000 // 主机超过5秒没有响应，则认为主机已经断开 sentinel failover-timeout mymaster 10000 // 主机超过10秒没有响应，则认为主机已经断开 sentinel parallel-syncs mymaster 1 // 主机超过1秒没有响应，则认为主机已经断开</p><p>配置密码认证（如果有） sentinel auth-pass mymaster yourpassword // 密码为yourpassword</p><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>1.缓存穿透:缓存中没有数据，数据库中也不存在数据,大量请求会请求到数据库，导致数据库压力过大 解决: 1.使用布隆过滤器 3.返回空结构体保存在缓存中</p><p>2.缓存雪崩:缓存中的数据全部失效，大量请求会触发缓存雪崩，导致数据库压力过大 解决: 1.限流降级，停用其他服务 3.加服务器容错 2.使用缓存预热，将数据预热到缓存中 3.缓存击穿:短时间内大量请求在缓存中获取数据，数据不存在，就会请求到数据库，数据库压力过大 解决: 1.使用分布式锁,只有一个请求获取锁成功，其他请求等待锁成功 2.热点数据不过期缓存</p>',57)]))}const d=e(a,[["render",u]]);export{h as __pageData,d as default};
